import { useState } from "react";

function Upload({ onUpload, isUploading }) {
  const [selectedFile, setSelectedFile] = useState(null);

  const handleSubmit = async (event) => {
    event.preventDefault();
    const form = event.currentTarget;

    if (!selectedFile) {
      return;
    }

    await onUpload(selectedFile);
    setSelectedFile(null);
    form.reset();
  };

  return (
    <section className="panel">
      <h2>Upload File</h2>
      <p className="panel-copy">
        Select a file and FileFinder will request a presigned URL, upload directly
        to S3, and save its metadata.
      </p>

      <form onSubmit={handleSubmit} className="stack">
        <label className="file-picker">
          <span>{selectedFile ? selectedFile.name : "Choose a file"}</span>
          <input
            type="file"
            onChange={(event) => setSelectedFile(event.target.files?.[0] || null)}
          />
        </label>

        <button type="submit" className="primary-button" disabled={!selectedFile || isUploading}>
          {isUploading ? "Uploading..." : "Upload"}
        </button>
      </form>
    </section>
  );
}

export default Upload;
